 29‚Üí/**
 30‚Üí * Binding + additional contextual information
 31‚Üí * Also defines equality over bindings.
 32‚Üí * https://stackoverflow.com/questions/5453226/java-need-a-hash-map-where-one-supplies-a-function-to-do-the-hashing
 33‚Üí */
 34‚Üíclass MappableBinding(val binding: Binding, private val screen: Screen) {
 35‚Üí    val isKey: Boolean get() = binding.isKey
 36‚Üí    val isKeyCode: Boolean get() = binding.isKeyCode
 37‚Üí
 38‚Üí    override fun equals(other: Any?): Boolean {
 39‚Üí        if (this === other) {
 40‚Üí            return true
 41‚Üí        }
 42‚Üí        if (other == null || javaClass != other.javaClass) {
 43‚Üí            return false
 44‚Üí        }
 45‚Üí        val otherMappableBinding = other as MappableBinding
 46‚Üí
 47‚Üí        val otherBinding = otherMappableBinding.binding
 48‚Üí        val bindingEquals = binding.keycode == otherBinding.keycode &&
 49‚Üí            binding.unicodeCharacter == otherBinding.unicodeCharacter &&
 50‚Üí            binding.gesture == otherBinding.gesture &&
 51‚Üí            modifierEquals(otherBinding.modifierKeys)
 52‚Üí
 53‚Üí        if (!bindingEquals) {
 54‚Üí            return false
 55‚Üí        }
 56‚Üí
 57‚Üí        return screen.screenEquals(otherMappableBinding.screen)
 58‚Üí    }
 59‚Üí
 60‚Üí    override fun hashCode(): Int {
 61‚Üí        // don't include the modifierKeys or mSide
 62‚Üí        return Objects.hash(binding.keycode, binding.unicodeCharacter, binding.gesture, screen.prefix)
 63‚Üí    }
 64‚Üí
 65‚Üí    private fun modifierEquals(keys: Binding.ModifierKeys?): Boolean {
 66‚Üí        // equals allowing subclasses
 67‚Üí        val thisKeys = binding.modifierKeys
 68‚Üí        if (thisKeys === keys) {
 69‚Üí            return true
 70‚Üí        }
 71‚Üí        // one is null
 72‚Üí        return if (keys == null || thisKeys == null) {
 73‚Üí            false
 74‚Üí        } else {
 75‚Üí            (thisKeys.shiftMatches(true) == keys.shiftMatches(true) || thisKeys.shiftMatches(false) == keys.shiftMatches(false)) &&
 76‚Üí                (thisKeys.ctrlMatches(true) == keys.ctrlMatches(true) || thisKeys.ctrlMatches(false) == keys.ctrlMatches(false)) &&
 77‚Üí                (thisKeys.altMatches(true) == keys.altMatches(true) || thisKeys.altMatches(false) == keys.altMatches(false))
 78‚Üí        }
 79‚Üí
 80‚Üí        // Perf: Could get a slight improvement if we check that both instances are not subclasses
 81‚Üí
 82‚Üí        // allow subclasses to work - a subclass which overrides shiftMatches will return true on one of the tests
 83‚Üí    }
 84‚Üí
 85‚Üí    fun toDisplayString(context: Context): String {
 86‚Üí        return screen.toDisplayString(context, binding)
 87‚Üí    }
