 93‚Üí    abstract class Screen private constructor(val prefix: Char) {
 94‚Üí        abstract fun toPreferenceString(binding: Binding): String?
 95‚Üí        abstract fun toDisplayString(context: Context, binding: Binding): String
 96‚Üí        abstract fun screenEquals(otherScreen: Screen): Boolean
 97‚Üí
 98‚Üí        class Reviewer(val side: CardSide) : Screen('r') {
 99‚Üí            override fun toPreferenceString(binding: Binding): String? {
100‚Üí                if (!binding.isValid) {
101‚Üí                    return null
102‚Üí                }
103‚Üí                val s = StringBuilder()
104‚Üí                s.append(prefix)
105‚Üí                s.append(binding.toString())
106‚Üí                // don't serialise problematic bindings
107‚Üí                if (s.isEmpty()) {
108‚Üí                    return null
109‚Üí                }
110‚Üí                when (side) {
111‚Üí                    CardSide.QUESTION -> s.append('0')
112‚Üí                    CardSide.ANSWER -> s.append('1')
113‚Üí                    CardSide.BOTH -> s.append('2')
114‚Üí                }
115‚Üí                return s.toString()
116‚Üí            }
117‚Üí
118‚Üí            override fun toDisplayString(context: Context, binding: Binding): String {
119‚Üí                val formatString = when (side) {
120‚Üí                    CardSide.QUESTION -> context.getString(R.string.display_binding_card_side_question)
121‚Üí                    CardSide.ANSWER -> context.getString(R.string.display_binding_card_side_answer)
122‚Üí                    else -> context.getString(R.string.display_binding_card_side_both) // intentionally no prefix
123‚Üí                }
124‚Üí                return String.format(formatString, binding.toDisplayString(context))
125‚Üí            }
126‚Üí
127‚Üí            override fun screenEquals(otherScreen: Screen): Boolean {
128‚Üí                val other: Reviewer = otherScreen as? Reviewer ?: return false
129‚Üí
130‚Üí                return side === CardSide.BOTH ||
131‚Üí                    other.side === CardSide.BOTH ||
132‚Üí                    side === other.side
133‚Üí            }
134‚Üí
135‚Üí            companion object {
136‚Üí                @CheckResult
137‚Üí                fun fromGesture(b: Binding): MappableBinding = MappableBinding(b, Reviewer(CardSide.BOTH))
138‚Üí                fun fromString(s: String): MappableBinding {
139‚Üí                    val binding = s.substring(0, s.length - 1)
140‚Üí                    val b = Binding.fromString(binding)
141‚Üí                    val side = when (s[s.length - 1]) {
142‚Üí                        '0' -> CardSide.QUESTION
143‚Üí                        '1' -> CardSide.ANSWER
144‚Üí                        else -> CardSide.BOTH
145‚Üí                    }
146‚Üí                    return MappableBinding(b, Reviewer(side))
147‚Üí                }
148‚Üí            }
149‚Üí        }
150‚Üí    }
151‚Üí
152‚Üí    /** the serialisation version */
153‚Üí    enum class Version {
154‚Üí        ONE
155‚Üí    }
156‚Üí
157‚Üí    companion object {
158‚Üí        const val PREF_SEPARATOR = '|'
159‚Üí
160‚Üí        @CheckResult
161‚Üí        fun fromGesture(gesture: Gesture): MappableBinding = MappableBinding(Binding(gesture), Screen.Reviewer(CardSide.BOTH))
162‚Üí
163‚Üí        @CheckResult
164‚Üí        fun fromGestureBinding(b: Binding): MappableBinding = MappableBinding(b, Screen.Reviewer(CardSide.BOTH))
165‚Üí
166‚Üí        @CheckResult
167‚Üí        fun List<MappableBinding>.toPreferenceString(): String = this.mapNotNull { it.toPreferenceString() }
168‚Üí            .joinToString(prefix = "1/", separator = PREF_SEPARATOR.toString())
169‚Üí
170‚Üí        @Suppress("UNUSED_PARAMETER")
171‚Üí        @CheckResult
172‚Üí        fun fromString(s: String, v: Version = Version.ONE): MappableBinding? {
173‚Üí            if (s.isEmpty()) {
174‚Üí                return null
175‚Üí            }
176‚Üí            return try {
177‚Üí                // the prefix of the serialized
178‚Üí                when (s[0]) {
179‚Üí                    'r' -> Screen.Reviewer.fromString(s.substring(1))
180‚Üí                    else -> null
181‚Üí                }
182‚Üí            } catch (e: Exception) {
183‚Üí                Timber.w(e, "failed to deserialize binding")
184‚Üí                null
185‚Üí            }
186‚Üí        }
187‚Üí
188‚Üí        @CheckResult
189‚Üí        fun fromPreferenceString(string: String?): MutableList<MappableBinding> {
190‚Üí            if (string.isNullOrEmpty()) return ArrayList()
191‚Üí            try {
192‚Üí                val version = string.takeWhile { x -> x != '/' }
193‚Üí                val remainder = string.substring(version.length + 1) // skip the /
194‚Üí                if (version != "1") {
195‚Üí                    Timber.w("cannot handle version '$version'")
196‚Üí                    return ArrayList()
197‚Üí                }
198‚Üí                return remainder.split(PREF_SEPARATOR).mapNotNull { fromString(it) }.toMutableList()
199‚Üí            } catch (e: Exception) {
200‚Üí                Timber.w(e, "Failed to deserialize preference")
201‚Üí                return ArrayList()
202‚Üí            }
203‚Üí        }
204‚Üí
205‚Üí        @CheckResult
206‚Üí        fun fromPreference(prefs: SharedPreferences, command: ViewerCommand): MutableList<MappableBinding> {
207‚Üí            val value = prefs.getString(command.preferenceKey, null) ?: return command.defaultValue.toMutableList()
208‚Üí            return fromPreferenceString(value)
209‚Üí        }
210‚Üí
211‚Üí        @CheckResult
212‚Üí        fun allMappings(prefs: SharedPreferences): MutableList<Pair<ViewerCommand, MutableList<MappableBinding>>> {
213‚Üí            return ViewerCommand.values().map {
214‚Üí                Pair(it, fromPreference(prefs, it))
215‚Üí            }.toMutableList()
216‚Üí        }
217‚Üí    }
218‚Üí}
