            R.id.action_flag_zero -> {
                Timber.i("Reviewer:: No flag")
                onFlag(currentCard, CardMarker.FLAG_NONE)
            }
            R.id.action_flag_one -> {
                Timber.i("Reviewer:: Flag one")
                onFlag(currentCard, CardMarker.FLAG_RED)
