                onFlag(currentCard, CardMarker.FLAG_ORANGE)
            }
            R.id.action_flag_three -> {
                Timber.i("Reviewer:: Flag three")
                onFlag(currentCard, CardMarker.FLAG_GREEN)
            }
            R.id.action_flag_four -> {
